import { useState } from 'react';
import { Mail, Phone, MapPin, Send, Github, Linkedin } from 'lucide-react';
// import { useToast } from '@/hooks/use-toast';

const Contact = () => {
  const { toast } = useToast();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    await new Promise(resolve => setTimeout(resolve, 1000));
    toast({
      title: "Message Sent!",
      description: "Thank you for reaching out. I'll get back to you soon!",
    });
    setFormData({ name: '', email: '', message: '' });
    setIsSubmitting(false);
  };

  const contactInfo = [
    {
      icon: Mail,
      label: "Email",
      value: "alex.johnson@example.com",
      href: "mailto:alex.johnson@example.com"
    },
    {
      icon: Phone,
      label: "Phone", 
      value: "+1 (555) 123-4567",
      href: "tel:+15551234567"
    },
    {
      icon: MapPin,
      label: "Location",
      value: "San Francisco, CA",
      href: "#"
    }
  ];

  return (
    <section id="contact" className="contact">
      <div className="contact-container container">
        <h2 className="section-title">Get In Touch</h2>

        <div className="contact-intro">
          <p className="contact-intro-text">
            I'm always open to discussing new opportunities, interesting projects, 
            or just having a friendly chat about technology. Feel free to reach out!
          </p>
        </div>

        <div className="contact-grid lg-grid-cols-2">
          <div>
            <h3 className="contact-info-title">Contact Information</h3>

            <div className="contact-info-list">
              {contactInfo.map((item, index) => (
                <a key={index} href={item.href} className="contact-info-item">
                  <div className="contact-info-icon">
                    <item.icon size={24} />
                  </div>
                  <div className="contact-info-text">
                    <p className="contact-info-label">{item.label}</p>
                    <p className="contact-info-value">{item.value}</p>
                  </div>
                </a>
              ))}
            </div>

            <div>
              <h4 className="contact-social-title">Connect With Me</h4>
              <div className="contact-social-links">
                <a href="https://github.com" target="_blank" rel="noopener noreferrer" className="contact-social-link">
                  <Github size={24} />
                </a>
                <a href="https://linkedin.com" target="_blank" rel="noopener noreferrer" className="contact-social-link">
                  <Linkedin size={24} />
                </a>
                <a href="mailto:alex.johnson@example.com" className="contact-social-link">
                  <Mail size={24} />
                </a>
              </div>
            </div>
          </div>

          <div className="contact-form">
            <h3 className="contact-form-title">Send Me a Message</h3>

            <form onSubmit={handleSubmit}>
              <div className="contact-form-group">
                <label htmlFor="name" className="contact-form-label">Full Name</label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  value={formData.name}
                  onChange={handleInputChange}
                  required
                  className="contact-form-input"
                  placeholder="Your full name"
                />
              </div>

              <div className="contact-form-group">
                <label htmlFor="email" className="contact-form-label">Email Address</label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  value={formData.email}
                  onChange={handleInputChange}
                  required
                  className="contact-form-input"
                  placeholder="your.email@example.com"
                />
              </div>

              <div className="contact-form-group">
                <label htmlFor="message" className="contact-form-label">Message</label>
                <textarea
                  id="message"
                  name="message"
                  value={formData.message}
                  onChange={handleInputChange}
                  required
                  rows={5}
                  className="contact-form-input contact-form-textarea"
                  placeholder="Tell me about your project or just say hello!"
                />
              </div>

              <button type="submit" disabled={isSubmitting} className="contact-form-submit">
                {isSubmitting ? (
                  <>
                    <div className="loading-spinner" />
                    Sending...
                  </>
                ) : (
                  <>
                    Send Message
                    <Send size={20} />
                  </>
                )}
              </button>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Contact;
